const [user, setUser] = useState({ name: 'Alice', age: 30 });

// WRONG — mutates existing object, same reference
function handleRename() {
  user.name = 'Bob';   // modifies the object React already holds
  setUser(user);       // passes back the same ref → no re-render
}

// CORRECT — spread creates a new object with a different reference
function handleRename() {
  setUser(prev => ({ ...prev, name: 'Bob' }));
}

const [form, setForm] = useState({ name: '', email: '', age: 0 });

// Update one field, keep others
function handleNameChange(e) {
  setForm(prev => ({ ...prev, name: e.target.value }));
}

// Generic handler using computed property name
function handleChange(e) {
  const { name, value } = e.target;
  setForm(prev => ({ ...prev, [name]: value }));
}

const [profile, setProfile] = useState({
  name: 'Alice',
  address: { city: 'London', zip: 'EC1A' },
});

// Update nested city — must spread BOTH levels
function updateCity(city) {
  setProfile(prev => ({
    ...prev,
    address: { ...prev.address, city },
  }));
}

// WRONG — shallow spread leaves the nested object mutated
function brokenUpdate(city) {
  setProfile(prev => ({
    ...prev,
    address: prev.address, // same reference — city mutation won't re-render nested consumers
  }));
  // And then mutating:
  // prev.address.city = city; // ← never do this
}

function TodoApp() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Buy milk', done: false },
    { id: 2, text: 'Walk dog', done: false },
  ]);

  // Add — spread creates a new array
  function addTodo(text) {
    setTodos(prev => [...prev, { id: Date.now(), text, done: false }]);
  }

  // Remove — filter returns a new array
  function removeTodo(id) {
    setTodos(prev => prev.filter(t => t.id !== id));
  }

  // Toggle — map returns a new array; spread creates a new item object
  function toggleTodo(id) {
    setTodos(prev =>
      prev.map(t => t.id === id ? { ...t, done: !t.done } : t)
    );
  }

  return (
    <ul>
      {todos.map(t => (
        <li key={t.id}>
          <span
            style={{ textDecoration: t.done ? 'line-through' : 'none' }}
            onClick={() => toggleTodo(t.id)}
          >
            {t.text}
          </span>
          <button onClick={() => removeTodo(t.id)}>x</button>
        </li>
      ))}
      <button onClick={() => addTodo('New task')}>Add</button>
    </ul>
  );
}

function SortableList({ items }) {
  const [list, setList] = useState(items);
  const [ascending, setAscending] = useState(true);

  function sortList() {
    setList(prev => {
      const copy = [...prev];             // copy FIRST
      copy.sort((a, b) =>
        ascending
          ? a.name.localeCompare(b.name)
          : b.name.localeCompare(a.name)
      );
      return copy;
    });
    setAscending(a => !a);
  }

  return (
    <>
      <button onClick={sortList}>{ascending ? '▲' : '▼'} Sort</button>
      <ul>{list.map(item => <li key={item.id}>{item.name}</li>)}</ul>
    </>
  );
}

function Scoreboard() {
  const [players, setPlayers] = useState([
    { id: 1, name: 'Alice', score: 0 },
    { id: 2, name: 'Bob',   score: 0 },
  ]);

  function addScore(id, points) {
    setPlayers(prev =>
      prev.map(p =>
        p.id === id
          ? { ...p, score: p.score + points } // new object for this player
          : p                                   // same reference for others
      )
    );
  }

  return (
    <table>
      <tbody>
        {players.map(p => (
          <tr key={p.id}>
            <td>{p.name}</td>
            <td>{p.score}</td>
            <td><button onClick={() => addScore(p.id, 10)}>+10</button></td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

function insertAt(arr, index, item) {
  return [
    ...arr.slice(0, index), // everything before the insertion point
    item,
    ...arr.slice(index),    // everything from the insertion point onwards
  ];
}

// Usage in a component
function handleInsert(index, newItem) {
  setItems(prev => insertAt(prev, index, newItem));
}

import { produce } from 'immer';

const [tree, setTree] = useState({
  root: { id: 1, children: [{ id: 2, name: 'Child', children: [] }] },
});

function renameNode(id, name) {
  setTree(prev =>
    produce(prev, draft => {
      // Looks like mutation, but Immer intercepts and produces a new object
      const node = draft.root.children.find(n => n.id === id);
      if (node) node.name = name;
    })
  );
}

