import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

test('toggleTodo creates a new reference and re-renders', async () => {
  const user = userEvent.setup();
  render(<TodoApp />);

  const item = screen.getByText('Buy milk');
  expect(item).not.toHaveStyle('text-decoration: line-through');

  await user.click(item);
  expect(item).toHaveStyle('text-decoration: line-through');

  await user.click(item);
  expect(item).not.toHaveStyle('text-decoration: line-through');
});

// WRONG: mutates first, then spreads
const next = { ...prev };
next.name = 'Bob'; // fine if next was just created
prev.name = 'Bob'; // still wrong — don't touch prev
setUser({ ...prev }); // new ref, but prev is now tainted

const copy = [...prev]; // new array — correct so far
copy[0].done = true;    // WRONG: mutates the same object that prev[0] points to

// Correct: also copy the item
copy[0] = { ...copy[0], done: true };

// WRONG: sort() mutates the existing array
setItems(prev => { prev.sort(); return prev; }); // same ref!

// CORRECT: copy then sort
setItems(prev => [...prev].sort());

// Pure helpers — no React dependency, easy to unit-test
export const addPlayer = player => prev => [...prev, player];
export const removePlayer = id => prev => prev.filter(p => p.id !== id);
export const updateScore = (id, delta) => prev =>
  prev.map(p => p.id === id ? { ...p, score: p.score + delta } : p);

// Component is minimal
function LeaderBoard() {
  const [players, setPlayers] = useState([]);

  return (
    <div>
      {players.map(p => (
        <div key={p.id}>
          {p.name}: {p.score}
          <button onClick={() => setPlayers(updateScore(p.id, 10))}>+10</button>
          <button onClick={() => setPlayers(removePlayer(p.id))}>Remove</button>
        </div>
      ))}
    </div>
  );
}

// Pure unit tests — no render needed
test('updateScore increments the right player', () => {
  const before = [{ id: 1, score: 0 }, { id: 2, score: 5 }];
  const after = updateScore(1, 10)(before);
  expect(after[0].score).toBe(10);
  expect(after[1].score).toBe(5);  // unchanged
  expect(after).not.toBe(before);  // new array
  expect(after[0]).not.toBe(before[0]); // new object for updated player
  expect(after[1]).toBe(before[1]);     // same ref for unchanged player
});

// Object.assign — creates a new object and copies properties
setUser(prev => Object.assign({}, prev, { name: 'Bob' }));

// Spread — equivalent, preferred for readability
setUser(prev => ({ ...prev, name: 'Bob' }));

// Both are shallow — neither deep-clones nested objects
// For nested objects you must spread each level that changes

function Cart() {
  const [cart, setCart] = useState([]); // [{ id, name, price, qty }]

  function addToCart(product) {
    setCart(prev => {
      const existing = prev.find(i => i.id === product.id);
      if (existing) {
        // Update qty — new array and new object for the matching item
        return prev.map(i =>
          i.id === product.id ? { ...i, qty: i.qty + 1 } : i
        );
      }
      // Add new item
      return [...prev, { ...product, qty: 1 }];
    });
  }

  function removeFromCart(id) {
    setCart(prev => prev.filter(i => i.id !== id));
  }

  function setQty(id, qty) {
    if (qty < 1) { removeFromCart(id); return; }
    setCart(prev =>
      prev.map(i => i.id === id ? { ...i, qty } : i)
    );
  }

  const total = cart.reduce((sum, i) => sum + i.price * i.qty, 0);

  return (
    <div>
      {cart.map(item => (
        <div key={item.id}>
          {item.name}
          <input
            type="number" value={item.qty} min={1}
            onChange={e => setQty(item.id, Number(e.target.value))}
          />
          <button onClick={() => removeFromCart(item.id)}>Remove</button>
        </div>
      ))}
      <p>Total: ${total.toFixed(2)}</p>
    </div>
  );
}
